    """Select recent complete turns without splitting OpenAI tool pairs."""
    builder = TurnBuilder()
    complete_turns = builder.complete_turns_only(builder.build(messages))
    selected = []
    selected_count = 0

    for turn in reversed(complete_turns):
        turn_size = len(turn.messages)
